const express = require('express');
const router = express.Router();

// Allowlist of valid redirect destinations
const ALLOWED_REDIRECTS = [
  '/dashboard',
  '/profile',
  '/account',
  '/home'
];

// Helper function to validate redirect URL
function isValidRedirect(url) {
  if (!url) return false;
  
  // Check if it's a relative path and matches our allowlist
  if (url.startsWith('/')) {
    return ALLOWED_REDIRECTS.includes(url);
  }
  
  // For absolute URLs, validate domain
  try {
    const parsedUrl = new URL(url);
    const allowedDomains = ['yourdomain.com', 'www.yourdomain.com'];
    return allowedDomains.includes(parsedUrl.hostname);
  } catch (error) {
    return false;
  }
}

// OAuth callback endpoint
router.get('/auth/callback', (req, res) => {
  // Simulate authentication logic
  const isAuthenticated = true; // This would be your actual auth logic
  
  if (!isAuthenticated) {
    return res.status(401).json({ error: 'Authentication failed' });
  }
  
  // Get return URL from query parameters
  const returnUrl = req.query.return_url || '/dashboard';
  
  // Validate the redirect URL
  if (!isValidRedirect(returnUrl)) {
    // If invalid, redirect to default page
    return res.redirect('/dashboard');
  }
  
  // Redirect to the intended destination
  res.redirect(returnUrl);
});

module.exports = router;